"use client";

import * as React from "react";
import {
  IconBus,
  IconTrain,
  IconShoppingBag,
  IconPlus,
  IconRefresh,
  IconSettings,
  IconCreditCard,
  IconBolt,
} from "@tabler/icons-react";
import {
  PageHeader,
  LoyaltySummaryCard,
  SegmentedControl,
  RadioCardGroup,
  RadioCard,
  AmountBreakdown,
  ListCard,
  BottomActionBar,
  StatGroup,
  Switch,
  Button,
  Badge,
  Card,
  CardContent,
  Separator,
  ToastProvider,
  useToast,
  formatCurrency,
} from "@gunjo/ui";

import {
  CARD,
  CHARGE_AMOUNTS,
  PAY_METHODS,
  AUTO_CHARGE,
  AUTO_THRESHOLDS,
  AUTO_AMOUNTS,
  BUS_REWARD,
  TXNS,
  type Txn,
  type TxnKind,
} from "./data";

const yen = (n: number) => formatCurrency(n, { currency: "JPY" });
/** 符号つき（+¥3,000 / −¥230） */
const yenSigned = (n: number) =>
  formatCurrency(Math.abs(n), { currency: "JPY" }).replace(
    "¥",
    n < 0 ? "−¥" : "+¥"
  );

type Section = "charge" | "history" | "settings";

interface AutoChargeState {
  enabled: boolean;
  threshold: number;
  amount: number;
}

/* ─────────────────────────────  残高ヒーロー  ───────────────────────────── */

function BalanceHero({ balance }: { balance: number }) {
  const rewardPct = Math.min(
    100,
    Math.round((BUS_REWARD.monthSpend / BUS_REWARD.nextThreshold) * 100)
  );
  return (
    <LoyaltySummaryCard
      meta={
        <span className="flex flex-col">
          <span className="font-medium text-primary-foreground">
            {CARD.brand}
          </span>
          <span>
            {CARD.nickname}・カード番号 •••• {CARD.last4}
          </span>
        </span>
      }
      tier={
        <Badge variant="secondary" icon={<IconBus />}>
          定期券一体
        </Badge>
      }
      balanceLabel="現在の残高"
      balance={yen(balance)}
      secondary={[
        { label: "定期区間", value: CARD.pass },
        {
          label: "最終利用",
          value: `${CARD.lastUsedAt}　${CARD.lastUsedWhere}`,
        },
      ]}
      progress={{
        value: BUS_REWARD.monthSpend,
        max: BUS_REWARD.nextThreshold,
        label: `バス利用特典まであと ${yen(
          BUS_REWARD.nextThreshold - BUS_REWARD.monthSpend
        )}`,
        caption: `${rewardPct}%`,
      }}
      alert={`当月バス利用 ${yen(BUS_REWARD.monthSpend)}・付与予定 ${
        BUS_REWARD.earnedPoints
      }P（${BUS_REWARD.rate}）`}
    />
  );
}

/* ─────────────────────────────  チャージ  ───────────────────────────── */

function ChargePanel({
  amount,
  onAmount,
  method,
  onMethod,
}: {
  amount: number;
  onAmount: (v: number) => void;
  method: string;
  onMethod: (v: string) => void;
}) {
  const selected = PAY_METHODS.find((m) => m.id === method) ?? PAY_METHODS[0];
  return (
    <section className="flex flex-col gap-5" aria-label="チャージ">
      {/* 金額のクイック選択 */}
      <div>
        <h2 className="mb-2 text-sm font-semibold text-foreground">
          チャージ金額
        </h2>
        <RadioCardGroup
          value={String(amount)}
          onValueChange={(v) => onAmount(Number(v))}
          aria-label="チャージ金額を選択"
          className="grid-cols-2"
        >
          {CHARGE_AMOUNTS.map((amt) => (
            <RadioCard
              key={amt}
              value={String(amt)}
              title={yen(amt)}
              highlight={amt === 10000 ? "一度にまとめてチャージ" : undefined}
            />
          ))}
        </RadioCardGroup>
      </div>

      {/* お支払い方法 */}
      <div>
        <h2 className="mb-2 text-sm font-semibold text-foreground">
          お支払い方法
        </h2>
        <RadioCardGroup
          value={method}
          onValueChange={onMethod}
          aria-label="お支払い方法を選択"
        >
          {PAY_METHODS.map((m) => (
            <RadioCard
              key={m.id}
              value={m.id}
              leading={<IconCreditCard className="size-5 text-muted-foreground" />}
              title={`${m.brand} •••• ${m.last4}`}
              description="登録済みクレジットカード"
              tags={
                m.primary ? (
                  <Badge variant="info">既定</Badge>
                ) : undefined
              }
            />
          ))}
        </RadioCardGroup>
      </div>

      {/* チャージ内訳 */}
      <Card>
        <CardContent className="p-4">
          <AmountBreakdown
            lines={[
              { label: "チャージ金額", amount },
              {
                label: "決済手数料",
                amount: 0,
                note: `${selected.brand} •••• ${selected.last4}`,
              },
            ]}
            total={{
              label: "お支払い金額",
              amount,
              tone: "neutral",
            }}
            formula={`チャージ後残高は ${yen(CARD.balance + amount)} になります`}
          />
        </CardContent>
      </Card>
    </section>
  );
}

/* ─────────────────────────────  利用履歴  ───────────────────────────── */

const KIND_META: Record<
  TxnKind,
  { icon: React.ReactNode; isCredit: boolean }
> = {
  fare: { icon: <IconBus className="size-5 text-muted-foreground" />, isCredit: false },
  charge: { icon: <IconPlus className="size-5 text-success-strong" />, isCredit: true },
  autocharge: { icon: <IconBolt className="size-5 text-success-strong" />, isCredit: true },
  shopping: { icon: <IconShoppingBag className="size-5 text-muted-foreground" />, isCredit: false },
  reward: { icon: <IconRefresh className="size-5 text-muted-foreground" />, isCredit: true },
};

/** 鉄道行はアイコンを差し替え */
function txnIcon(t: Txn): React.ReactNode {
  if (t.kind === "fare" && t.title.includes("鉄道"))
    return <IconTrain className="size-5 text-muted-foreground" />;
  return KIND_META[t.kind].icon;
}

const WEEKDAYS = ["日", "月", "火", "水", "木", "金", "土"];
function formatDateHeading(iso: string): string {
  const [y, m, d] = iso.split("-").map(Number);
  const wd = WEEKDAYS[new Date(y, m - 1, d).getDay()];
  return `${m}月${d}日（${wd}）`;
}

function HistoryPanel() {
  // 日付グルーピング — ライブラリに日付グループ化リスト/SectionListが無いので手組み。
  const groups = React.useMemo(() => {
    const map = new Map<string, Txn[]>();
    for (const t of TXNS) {
      const arr = map.get(t.date) ?? [];
      arr.push(t);
      map.set(t.date, arr);
    }
    return Array.from(map.entries());
  }, []);

  return (
    <section className="flex flex-col gap-5" aria-label="利用履歴">
      {/* 当月サマリ（バス特典） */}
      <StatGroup
        cols={3}
        items={[
          { label: "当月バス利用", value: yen(BUS_REWARD.monthSpend) },
          {
            label: "付与予定P",
            value: `${BUS_REWARD.earnedPoints}P`,
            hint: BUS_REWARD.rate,
          },
          {
            label: "次の還元まで",
            value: yen(BUS_REWARD.nextThreshold - BUS_REWARD.monthSpend),
          },
        ]}
      />

      <div className="flex flex-col gap-4">
        {groups.map(([date, items]) => (
          <div key={date}>
            <h3 className="mb-2 px-1 text-xs font-semibold text-muted-foreground">
              {formatDateHeading(date)}
            </h3>
            <div className="flex flex-col gap-2">
              {items.map((t) => {
                const credit = KIND_META[t.kind].isCredit;
                return (
                  <ListCard
                    key={t.id}
                    leading={txnIcon(t)}
                    title={t.title}
                    description={`${t.time}　${t.detail ?? ""}`}
                    meta={`残高 ${yen(t.balanceAfter)}`}
                    trailing={null}
                    status={
                      <span
                        className={
                          "whitespace-nowrap text-base font-bold tabular-nums " +
                          (credit ? "text-success-strong" : "text-foreground")
                        }
                      >
                        <span className="sr-only">
                          {credit ? "入金 " : "利用 "}
                        </span>
                        {yenSigned(t.amount)}
                      </span>
                    }
                  />
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}

/* ─────────────────────────────  設定（オートチャージ）  ───────────────────────────── */

function SettingsPanel({
  auto,
  setAuto,
}: {
  auto: AutoChargeState;
  setAuto: React.Dispatch<React.SetStateAction<AutoChargeState>>;
}) {
  return (
    <section className="flex flex-col gap-5" aria-label="設定">
      <Card>
        <CardContent className="flex flex-col gap-4 p-4">
          <div className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <h2 className="text-sm font-semibold text-foreground">
                オートチャージ
              </h2>
              <p className="mt-0.5 text-xs text-muted-foreground">
                残高が設定額を下回ると、改札・乗車時に自動でチャージします。
              </p>
            </div>
            <Switch
              checked={auto.enabled}
              onCheckedChange={(v) => setAuto((s) => ({ ...s, enabled: v }))}
              aria-label="オートチャージの有効・無効"
            />
          </div>

          {auto.enabled && (
            <>
              <Separator />
              <div>
                <p className="mb-1.5 text-xs font-medium text-foreground">
                  残高がこの金額以下になったら
                </p>
                <SegmentedControl
                  size="lg"
                  aria-label="オートチャージのしきい値"
                  value={String(auto.threshold)}
                  onValueChange={(v) =>
                    setAuto((s) => ({ ...s, threshold: Number(v) }))
                  }
                  options={AUTO_THRESHOLDS.map((t) => ({
                    value: String(t),
                    label: yen(t),
                  }))}
                />
              </div>
              <div>
                <p className="mb-1.5 text-xs font-medium text-foreground">
                  この金額をチャージ
                </p>
                <SegmentedControl
                  size="lg"
                  aria-label="オートチャージの金額"
                  value={String(auto.amount)}
                  onValueChange={(v) =>
                    setAuto((s) => ({ ...s, amount: Number(v) }))
                  }
                  options={AUTO_AMOUNTS.map((a) => ({
                    value: String(a),
                    label: yen(a),
                  }))}
                />
              </div>
              <p className="rounded-md bg-muted px-3 py-2 text-xs text-muted-foreground">
                残高 {yen(auto.threshold)} 以下で {yen(auto.amount)} を
                自動チャージ（{PAY_METHODS.find((m) => m.primary)?.brand} ••••{" "}
                {PAY_METHODS.find((m) => m.primary)?.last4}）
              </p>
            </>
          )}
        </CardContent>
      </Card>
    </section>
  );
}

/* ─────────────────────────────  画面本体  ───────────────────────────── */

function BusIcScreen() {
  const { showToast } = useToast();
  const [section, setSection] = React.useState<Section>("charge");
  const [balance, setBalance] = React.useState<number>(CARD.balance);
  const [amount, setAmount] = React.useState<number>(2000);
  const [method, setMethod] = React.useState<string>(
    PAY_METHODS.find((m) => m.primary)?.id ?? PAY_METHODS[0].id
  );
  const [auto, setAuto] = React.useState<AutoChargeState>({
    enabled: AUTO_CHARGE.enabled,
    threshold: AUTO_CHARGE.threshold,
    amount: AUTO_CHARGE.amount,
  });

  const handleCharge = () => {
    setBalance((b) => b + amount);
    const m = PAY_METHODS.find((x) => x.id === method);
    showToast(
      `${yen(amount)} をチャージしました（${m?.brand} •••• ${m?.last4}）`,
      "success"
    );
  };

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-muted/30">
      <PageHeader
        title="モバイルIC・チャージ"
        subtitle={CARD.brand}
        onBack={() => undefined}
        actions={
          <Button
            variant="ghost"
            size="icon"
            aria-label="設定"
            onClick={() => setSection("settings")}
          >
            <IconSettings className="size-5" />
          </Button>
        }
      />

      <main className="flex flex-1 flex-col gap-5 px-4 py-4">
        <BalanceHero balance={balance} />

        <SegmentedControl
          size="lg"
          aria-label="表示の切り替え"
          value={section}
          onValueChange={(v) => setSection(v as Section)}
          options={[
            { value: "charge", label: "チャージ" },
            { value: "history", label: "利用履歴" },
            { value: "settings", label: "設定" },
          ]}
        />

        {section === "charge" && (
          <ChargePanel
            amount={amount}
            onAmount={setAmount}
            method={method}
            onMethod={setMethod}
          />
        )}
        {section === "history" && <HistoryPanel />}
        {section === "settings" && (
          <SettingsPanel auto={auto} setAuto={setAuto} />
        )}
      </main>

      {section === "charge" && (
        <BottomActionBar
          actions={
            <Button size="lg" variant="primary" onClick={handleCharge}>
              {yen(amount)} をチャージ
            </Button>
          }
        >
          <span className="flex flex-col">
            <span className="text-xs text-muted-foreground">
              チャージ後残高
            </span>
            <span className="text-base font-bold tabular-nums text-foreground">
              {yen(balance + amount)}
            </span>
          </span>
        </BottomActionBar>
      )}
    </div>
  );
}

export default function BusIcPage() {
  return (
    <ToastProvider>
      <BusIcScreen />
    </ToastProvider>
  );
}

/**
 * モバイルIC・残高チャージ — リアルなサンプルデータ。
 * 架空の交通系IC「みなと交通IC（PASMO/Suica相当）」を、群青バス（架空の路線バス事業者）の
 * アプリ内で表示する想定。金額はすべて円（整数）。
 */

export type TxnKind = "fare" | "charge" | "shopping" | "autocharge" | "reward";

export interface Txn {
  id: string;
  /** ISO日付（YYYY-MM-DD）— 日付グルーピングのキー */
  date: string;
  /** 利用日時の時刻表示（HH:mm） */
  time: string;
  kind: TxnKind;
  /** 行のタイトル（系統名／チャージ／物販店名 など） */
  title: string;
  /** 区間・店舗・補足（系統の起終点 など） */
  detail?: string;
  /** 符号つき金額。マイナス=利用（運賃/物販）、プラス=入金（チャージ） */
  amount: number;
  /** 取引後残高 */
  balanceAfter: number;
}

